const sequence = $input.first().json;
const steps = JSON.parse(sequence.steps || '[]');
const orgId = $('Start').first().json.org_id;
const eventId = $('Start').first().json.event_id;
const customerId = $('Start').first().json.customer_id;

const now = new Date();
const attempts = steps.map(step => ({
  org_id: orgId,
  payment_event_id: eventId,
  customer_id: customerId,
  sequence_id: sequence.id,
  template_id: step.template_id || null,
  step_number: step.step,
  type: step.type === 'retry' ? 'auto_retry' : step.type,
  status: 'scheduled',
  scheduled_at: new Date(now.getTime() + step.delay_hours * 3600000).toISOString(),
}));

return attempts;
